  @ApiPropertyOptional({ description: 'UUID подписок-референсных источников', type: [String] })
  @IsOptional()
  @IsArray()
  @ArrayMinSize(1)
  @IsUUID('4', { each: true })
  referenceSubscriptionIds?: string[];

  @ApiPropertyOptional({ description: 'Актив для фиксации прибыли' })
  @IsOptional()
  @IsString()
  @IsNotEmpty()
  profitAsset?: string;

  @ApiPropertyOptional({ description: 'Проскальзывание (0–1)' })
  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(1)
  slippage?: number;

  @ApiPropertyOptional({ description: 'Начальный баланс' })
  @IsOptional()
  @IsNumber()
  @Min(0)
  initialBalance?: number;

  @ApiPropertyOptional({ description: 'Порог автопокупки (%)' })
  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(100)
  autoBuyThresholdPct?: number;

  @ApiPropertyOptional({ description: 'Порог автопродажи (%)' })
  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(100)
  autoSellThresholdPct?: number;

  @ApiPropertyOptional({ description: 'Trailing take-profit (%)' })
  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(100)
  trailingTakeProfitPct?: number;

  @ApiPropertyOptional({ description: 'Стоп-лосс (%)' })
  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(100)
  stopLossPct?: number;

  @ApiPropertyOptional({ description: '% от баланса для сделки' })
  @IsOptional()
  @IsNumber()
  @Min(0)
  @Max(100)
  tradeAmountPct?: number;
}

import {
  Entity,
  PrimaryGeneratedColumn,
  Column,
  CreateDateColumn,
  ManyToOne,
  OneToMany,
  JoinColumn,
} from 'typeorm';
import { User } from '../../users/entities/user.entity';
import { Subscription } from '../../subscriptions/entities/subscription.entity';
import { ArbiConfigSource } from './arbi-config-source.entity';

@Entity('arbi_configs')
export class ArbiConfig {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column()
  userId: string;

  @ManyToOne(() => User, { onDelete: 'CASCADE' })
  @JoinColumn({ name: 'userId' })
  user: User;

  @Column({ length: 255 })
  name: string;

  @Column()
  tradingSubscriptionId: string;

  @ManyToOne(() => Subscription, { onDelete: 'CASCADE' })
  @JoinColumn({ name: 'tradingSubscriptionId' })
  tradingSubscription: Subscription;

  @Column({ length: 20, default: 'USDC' })
  profitAsset: string;

  @Column('decimal', { precision: 5, scale: 4, default: 0.01 })
  slippage: number;

  @Column('decimal', { precision: 12, scale: 2, default: 100 })
  initialBalance: number;

  @OneToMany(() => ArbiConfigSource, (s) => s.config, {
    cascade: true,
    eager: true,
  })
  sources: ArbiConfigSource[];

  @CreateDateColumn()
  createdAt: Date;
}

import {
  Entity,
  PrimaryGeneratedColumn,
  Column,
  CreateDateColumn,
  ManyToOne,
  OneToMany,
  JoinColumn,
} from 'typeorm';
import { User } from '../../users/entities/user.entity';
import { Subscription } from '../../subscriptions/entities/subscription.entity';
import { ArbiConfigSource } from './arbi-config-source.entity';

@Entity('arbi_configs')
export class ArbiConfig {
  @PrimaryGeneratedColumn('uuid')
  id: string;

  @Column()
  userId: string;

  @ManyToOne(() => User, { onDelete: 'CASCADE' })
  @JoinColumn({ name: 'userId' })
  user: User;

  @Column({ length: 255 })
  name: string;

  @Column()
  tradingSubscriptionId: string;

  @ManyToOne(() => Subscription, { onDelete: 'CASCADE' })
  @JoinColumn({ name: 'tradingSubscriptionId' })
  tradingSubscription: Subscription;

  @Column({ length: 20, default: 'USDC' })
  profitAsset: string;

  @Column('decimal', { precision: 5, scale: 4, default: 0.01 })
  slippage: number;

  @Column('decimal', { precision: 12, scale: 2, default: 100 })
  initialBalance: number;

  // ── Секция 2: Параметры автоторговли ──

  /** На сколько % цена покупки на торгуемом источнике должна быть ниже средней reference → автопокупка */
  @Column('decimal', { precision: 7, scale: 4, nullable: true, default: null })
  autoBuyThresholdPct: number | null;

  /** На сколько % цена продажи на торгуемом источнике должна быть выше средней reference → автопродажа */
  @Column('decimal', { precision: 7, scale: 4, nullable: true, default: null })
  autoSellThresholdPct: number | null;

  /** % отката от максимума цены продажи → trailing автопродажа */
  @Column('decimal', { precision: 7, scale: 4, nullable: true, default: null })
  trailingTakeProfitPct: number | null;

  /** % убытка от цены покупки → принудительная продажа (стоп-лосс) */
  @Column('decimal', { precision: 7, scale: 4, nullable: true, default: null })
  stopLossPct: number | null;

  /** Какой % от баланса использовать при каждой сделке */
  @Column('decimal', { precision: 7, scale: 4, default: 100 })
  tradeAmountPct: number;

  @OneToMany(() => ArbiConfigSource, (s) => s.config, {
    cascade: true,
    eager: true,
  })
  sources: ArbiConfigSource[];

  @CreateDateColumn()
  createdAt: Date;
}

import { Injectable, NotFoundException, BadRequestException, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { ConfigService } from '@nestjs/config';
import { HttpService } from '@nestjs/axios';
import { firstValueFrom } from 'rxjs';
import { Subscription } from '../subscriptions/entities/subscription.entity';
import { buildStoreKeys, detectKeyFormat, SOURCE_META } from './market-data-keys';

/** Точка из PriceStore arbiDexServerBots */
interface BotsPricePoint {
  t: number; // timestamp ms
  v: number; // value
}

/** Ответ от /prices/keys (POST) — каждый ключ содержит объект с полем points */
interface BotsPriceKeyData {
  points: BotsPricePoint[];
  count?: number;
  last?: BotsPricePoint;
}

interface BotsPriceKeysResponse {
  [key: string]: BotsPriceKeyData;
}

/** Конфиг серии для фронтенда */
export interface PriceSeriesConfig {
  key: string;
  name: string;
  color: string;
}

/** Точка данных для фронтенда */
export interface ChartPricePoint {
  time: number;
  [field: string]: number;
}

/** Полный ответ для фронтенда */
export interface SubscriptionPriceData {
  series: PriceSeriesConfig[];
  data: ChartPricePoint[];
}

@Injectable()
export class PricesService {
  private readonly logger = new Logger(PricesService.name);
  private readonly marketDataUrl: string;

  constructor(
    private readonly httpService: HttpService,
    private readonly configService: ConfigService,
    @InjectRepository(Subscription)
    private readonly subsRepo: Repository<Subscription>,
  ) {
    this.marketDataUrl = this.configService.get<string>('marketData.url') ?? 'http://45.135.182.251:3002';
  }

  /**
   * Получить ценовые данные по subscriptionId.
   * Маппит sourceId+pairId → ключи PriceStore, запрашивает историю из arbiDexServerBots,
   * трансформирует в формат PriceChartComponent.
   */
  async getPricesBySubscription(subscriptionId: string, userId: string): Promise<SubscriptionPriceData> {
    // 1. Найти подписку
    const sub = await this.subsRepo.findOne({ where: { id: subscriptionId, userId } });
    if (!sub) {
      throw new NotFoundException('Подписка не найдена');
    }

    // 2. Определяем формат ключей и строим bid/ask ключи
    let format: 'pipe' | 'concat' = 'concat';
    try {
      const keysResp = await firstValueFrom(
        this.httpService.get<string[]>(`${this.marketDataUrl}/store/keys`),
      );
      format = detectKeyFormat(keysResp.data);
    } catch {
      // используем формат по умолчанию
    }

    const keys = buildStoreKeys(sub.sourceId, sub.pairId, format);
    if (!keys) {
      throw new BadRequestException(
        `Не удалось построить ключи для sourceId="${sub.sourceId}", pairId="${sub.pairId}".`,
      );
    }

    // 3. Запрос к arbiDexMarketData
    const { bidKey, askKey } = keys;
    let botsData: BotsPriceKeysResponse;

    try {
      const response = await firstValueFrom(
        this.httpService.post<BotsPriceKeysResponse>(`${this.marketDataUrl}/store/keys`, {
          keys: [bidKey, askKey],
        }),
      );
      botsData = response.data;
    } catch (error) {
      this.logger.error(`Ошибка при запросе к arbiDexMarketData: ${error.message}`);
      throw new BadRequestException(
        `Не удалось получить данные от сервиса котировок (${this.marketDataUrl}). ` +
        `Убедитесь что arbiDexMarketData запущен.`,
      );
    }

    // 4. Трансформация в формат PriceChartComponent
    const bidPoints: BotsPricePoint[] = botsData[bidKey]?.points ?? [];
    const askPoints: BotsPricePoint[] = botsData[askKey]?.points ?? [];

    // Определяем тип источника: DEX показываем bid/ask, CEX — только mid
    const isDex = sub.sourceId.startsWith('dex');

    // Merge bid и ask по timestamp с помощью Map
    const timeMap = new Map<number, ChartPricePoint>();

    for (const p of bidPoints) {
      timeMap.set(p.t, { time: p.t, bidPrice: p.v, askPrice: 0 });
    }

    for (const p of askPoints) {
      const existing = timeMap.get(p.t);
      if (existing) {
        existing.askPrice = p.v;
      } else {
        timeMap.set(p.t, { time: p.t, bidPrice: 0, askPrice: p.v });
      }
    }

    // Сортировка по времени, заполнение пропусков предыдущим значением
    const sorted = Array.from(timeMap.values()).sort((a, b) => a.time - b.time);

    let lastBid = 0;
    let lastAsk = 0;
    for (const point of sorted) {
      if (point.bidPrice === 0 && lastBid !== 0) point.bidPrice = lastBid;
    // 5. Конфиг серий
      lastBid = point.bidPrice;
      lastAsk = point.askPrice;
    }

    // 5. Конфиг серий — единый формат bid/ask для всех источников (DEX и CEX)
    if (isDex) {
      // DEX: две серии — bid и ask
      const series: PriceSeriesConfig[] = [
        { key: 'bidPrice', name: `${sourceName} Bid`, color: '#0ecb81' },
      return { series, data: sorted };
    } else {
      // CEX: одна серия — mid (среднее bid и ask)
      const midData: ChartPricePoint[] = sorted.map((point) => ({
        time: point.time,
        midPrice:
          point.bidPrice > 0 && point.askPrice > 0
            ? (point.bidPrice + point.askPrice) / 2
            : point.bidPrice || point.askPrice,
      }));

      const series: PriceSeriesConfig[] = [
        { key: 'midPrice', name: `${sourceName} Mid`, color: '#2196f3' },
      ];

      return { series, data: midData };
    }
      ];
    ];

    return { series, data: sorted };
  }
}

